Index: bench-targets/cli-flags/src/parseArgs.mjs
===================================================================
--- bench-targets/cli-flags/src/parseArgs.mjs	
+++ bench-targets/cli-flags/src/parseArgs.mjs	
@@ -1,9 +1,36 @@
 export function parseArgs(argv) {
   const result = { _: [] }
-  for (let index = 0; index < argv.length; index += 1) {
-    const arg = argv[index]
-    if (!arg.startsWith('--')) result._.push(arg)
-    else result[arg.slice(2)] = true
+  let i = 0
+  while (i < argv.length) {
+    const arg = argv[i]
+    if (arg.startsWith('-')) {
+      if (arg.startsWith('---')) {
+        result._.push(arg)
+        i++
+        continue
+      }
+      if (arg.includes('=')) {
+        const equalsIndex = arg.indexOf('=')
+        const key = arg.slice(2, equalsIndex)
+        const value = arg.slice(equalsIndex + 1)
+        result[key] = value || true
+        i++
+        continue
+      }
+      if (i + 1 < argv.length) {
+        const next = argv[i + 1]
+        if (!next.startsWith('-')) {
+          result[arg.slice(2)] = next
+          i += 2
+          continue
+        }
+      }
+      result[arg.slice(2)] = true
+      i++
+      continue
+    }
+    result._.push(arg)
+    i++
   }
   return result
 }

